/* ============================================
   ROLLER COASTER MEDIA — Brand stylesheet
   Palette: Pure black + crisp white + magenta dot accent
   Type:    Bold sans-serif (Inter / system stack)
   ============================================ */

/* ---------- DESIGN TOKENS ---------- */
:root {
    --rcm-black: #000000;
    --rcm-off-black: #0a0a0a;
    --rcm-surface: #111111;
    --rcm-surface-2: #161616;
    --rcm-border: #1f1f1f;
    --rcm-border-strong: #2a2a2a;
    --rcm-text: #ffffff;
    --rcm-text-muted: #9a9a9a;
    --rcm-text-dim: #6b6b6b;
    --rcm-magenta: #d11e5f;
    --rcm-magenta-bright: #ec1d6e;
    --rcm-magenta-soft: rgba(209, 30, 95, 0.12);

    --max-w: 1280px;
    --gutter: clamp(1.25rem, 4vw, 2.5rem);

    --radius-sm: 6px;
    --radius: 14px;
    --radius-lg: 22px;
    --radius-pill: 999px;

    --ease: cubic-bezier(.2, .8, .2, 1);

    --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI",
        Roboto, Helvetica, Arial, sans-serif;
}

/* ---------- RESET ---------- */
*, *::before, *::after { box-sizing: border-box; }
html { -webkit-text-size-adjust: 100%; scroll-behavior: smooth; }
body {
    margin: 0;
    background: var(--rcm-black);
    color: var(--rcm-text);
    font-family: var(--font-sans);
    font-size: 16px;
    line-height: 1.55;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    overflow-x: hidden;
}
img, svg { max-width: 100%; display: block; }
a { color: inherit; text-decoration: none; }
button { font: inherit; cursor: pointer; }
input, textarea, select { font: inherit; color: inherit; }

/* ---------- TYPOGRAPHY ---------- */
h1, h2, h3, h4 {
    margin: 0 0 .4em;
    font-weight: 800;
    letter-spacing: -0.02em;
    line-height: 1.04;
}
h1 { font-size: clamp(2.6rem, 7vw, 6rem); }
h2 { font-size: clamp(2rem, 4.5vw, 3.6rem); }
h3 { font-size: clamp(1.35rem, 2.2vw, 1.8rem); }
h4 { font-size: 1.1rem; letter-spacing: 0; }
p  { margin: 0 0 1em; color: var(--rcm-text-muted); }

.eyebrow {
    display: inline-flex;
    align-items: center;
    gap: .55rem;
    font-size: .78rem;
    font-weight: 600;
    letter-spacing: .22em;
    text-transform: uppercase;
    color: var(--rcm-text);
    padding: .45rem .9rem;
    border: 1px solid var(--rcm-border-strong);
    border-radius: var(--radius-pill);
    background: var(--rcm-surface);
}
.eyebrow::before {
    content: "";
    width: .45rem; height: .45rem;
    border-radius: 50%;
    background: var(--rcm-magenta);
    box-shadow: 0 0 12px var(--rcm-magenta);
}

/* Magenta dot — signature brand mark */
.dot {
    display: inline-block;
    width: .55em; height: .55em;
    background: var(--rcm-magenta);
    border-radius: 50%;
    vertical-align: baseline;
    margin-left: .05em;
    transform: translateY(-.04em);
}
.accent { color: var(--rcm-magenta); }

/* ---------- LAYOUT ---------- */
.container {
    max-width: var(--max-w);
    margin: 0 auto;
    padding: 0 var(--gutter);
}
section { padding: clamp(4rem, 9vw, 7rem) 0; position: relative; }
.section-head { max-width: 760px; margin-bottom: 3rem; }
.section-head h2 { margin-bottom: .6rem; }
.section-head p { font-size: 1.05rem; max-width: 580px; }

/* ---------- BUTTONS ---------- */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: .65rem;
    padding: .95rem 1.65rem;
    border-radius: var(--radius-pill);
    font-weight: 600;
    font-size: .95rem;
    letter-spacing: -0.01em;
    border: 1px solid transparent;
    transition: transform .25s var(--ease), background .25s, color .25s, border-color .25s;
    white-space: nowrap;
}
.btn:hover { transform: translateY(-2px); }
.btn-primary {
    background: var(--rcm-magenta);
    color: #fff;
    box-shadow: 0 12px 30px -10px rgba(209, 30, 95, .55);
}
.btn-primary:hover { background: var(--rcm-magenta-bright); }
.btn-ghost {
    background: transparent;
    color: var(--rcm-text);
    border-color: var(--rcm-border-strong);
}
.btn-ghost:hover { background: #fff; color: var(--rcm-black); border-color: #fff; }
.btn-white { background: #fff; color: var(--rcm-black); }
.btn-white:hover { background: var(--rcm-magenta); color: #fff; }
.btn .arrow { transition: transform .25s var(--ease); }
.btn:hover .arrow { transform: translateX(4px); }

/* ---------- NAVBAR ---------- */
.nav {
    position: sticky;
    top: 0; z-index: 80;
    background: rgba(0, 0, 0, .75);
    backdrop-filter: blur(14px);
    -webkit-backdrop-filter: blur(14px);
    border-bottom: 1px solid var(--rcm-border);
}
.nav-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 1.1rem 0;
}
.brand {
    display: inline-flex;
    align-items: center;
    gap: .55rem;
    font-weight: 800;
    font-size: 1.05rem;
    letter-spacing: -0.02em;
}
.brand .mark {
    width: 28px; height: 28px;
    background: #fff;
    color: var(--rcm-black);
    border-radius: 7px;
    display: grid; place-items: center;
    font-size: .9rem;
    font-weight: 900;
    position: relative;
}
.brand .mark::after {
    content: "";
    position: absolute;
    width: 7px; height: 7px;
    background: var(--rcm-magenta);
    border-radius: 50%;
    right: -3px; bottom: -3px;
}
.nav-links {
    display: flex; gap: 2rem;
    list-style: none; margin: 0; padding: 0;
}
.nav-links a {
    font-size: .94rem;
    color: var(--rcm-text-muted);
    font-weight: 500;
    position: relative;
    transition: color .2s;
}
.nav-links a:hover,
.nav-links a.active { color: #fff; }
.nav-links a.active::after {
    content: "";
    position: absolute;
    left: 50%; bottom: -8px;
    width: 5px; height: 5px;
    background: var(--rcm-magenta);
    border-radius: 50%;
    transform: translateX(-50%);
}
.nav-cta { display: inline-flex; align-items: center; gap: .8rem; }
.menu-toggle {
    display: none;
    background: transparent;
    border: 1px solid var(--rcm-border-strong);
    border-radius: 10px;
    width: 42px; height: 42px;
    place-items: center;
    color: #fff;
}

@media (max-width: 880px) {
    .nav-links {
        position: fixed;
        inset: 64px 0 auto 0;
        flex-direction: column;
        background: var(--rcm-black);
        padding: 1.5rem var(--gutter) 2rem;
        gap: 1.2rem;
        border-bottom: 1px solid var(--rcm-border);
        transform: translateY(-110%);
        transition: transform .35s var(--ease);
    }
    .nav-links.open { transform: translateY(0); }
    .nav-links a { font-size: 1.1rem; color: #fff; }
    .menu-toggle { display: grid; }
    .nav-cta .btn { display: none; }
}

/* ---------- HERO (big poster type) ---------- */
.hero {
    padding-top: clamp(3rem, 7vw, 5rem);
    padding-bottom: clamp(3rem, 7vw, 5rem);
    position: relative;
    overflow: hidden;
}
.hero::before {
    content: "";
    position: absolute;
    width: 700px; height: 700px;
    background: radial-gradient(closest-side, rgba(209, 30, 95, .25), transparent 70%);
    top: -250px; right: -200px;
    filter: blur(20px);
    pointer-events: none;
}
.hero-grid {
    display: grid;
    grid-template-columns: 1.4fr 1fr;
    gap: clamp(2rem, 6vw, 5rem);
    align-items: end;
}
.hero h1 {
    font-size: clamp(3rem, 11vw, 9rem);
    font-weight: 900;
    text-transform: uppercase;
    letter-spacing: -0.04em;
    line-height: .92;
}
.hero h1 span.line { display: block; }
.hero .sub {
    font-size: clamp(1rem, 1.3vw, 1.15rem);
    color: var(--rcm-text-muted);
    max-width: 460px;
    margin: 0 0 2rem;
}
.hero-tag {
    font-size: .8rem;
    letter-spacing: .3em;
    text-transform: uppercase;
    color: var(--rcm-text-dim);
    margin-bottom: 1.5rem;
}
.hero-actions { display: flex; gap: 1rem; flex-wrap: wrap; }

@media (max-width: 880px) {
    .hero-grid { grid-template-columns: 1fr; }
}

/* ---------- MARQUEE TRUST STRIP ---------- */
.marquee {
    border-block: 1px solid var(--rcm-border);
    background: var(--rcm-off-black);
    padding: 1.4rem 0;
    overflow: hidden;
}
.marquee-track {
    display: flex;
    gap: 4rem;
    white-space: nowrap;
    animation: scroll 35s linear infinite;
    width: max-content;
}
.marquee-item {
    font-weight: 700;
    font-size: 1.4rem;
    letter-spacing: -0.02em;
    color: var(--rcm-text-muted);
    display: inline-flex;
    align-items: center;
    gap: 1rem;
}
.marquee-item::after {
    content: "";
    width: 6px; height: 6px;
    background: var(--rcm-magenta);
    border-radius: 50%;
    display: inline-block;
}
@keyframes scroll {
    from { transform: translateX(0); }
    to   { transform: translateX(-50%); }
}

/* ---------- STAT STRIP ---------- */
.stats {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 1px;
    background: var(--rcm-border);
    border: 1px solid var(--rcm-border);
    border-radius: var(--radius-lg);
    overflow: hidden;
}
.stat {
    background: var(--rcm-black);
    padding: 2rem;
}
.stat .n {
    font-size: clamp(2.4rem, 4.5vw, 3.6rem);
    font-weight: 900;
    letter-spacing: -0.04em;
    line-height: 1;
    margin: 0 0 .5rem;
}
.stat .n .dot { width: .25em; height: .25em; vertical-align: middle; }
.stat .l {
    font-size: .82rem;
    letter-spacing: .15em;
    text-transform: uppercase;
    color: var(--rcm-text-muted);
}
@media (max-width: 720px) {
    .stats { grid-template-columns: repeat(2, 1fr); }
}

/* ---------- SERVICE CARDS ---------- */
.cards {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1.2rem;
}
@media (max-width: 980px) { .cards { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 640px) { .cards { grid-template-columns: 1fr; } }

.card {
    background: var(--rcm-surface);
    border: 1px solid var(--rcm-border);
    border-radius: var(--radius-lg);
    padding: 2rem 1.8rem;
    position: relative;
    overflow: hidden;
    transition: border-color .3s var(--ease), transform .3s var(--ease);
}
.card:hover {
    border-color: var(--rcm-magenta);
    transform: translateY(-4px);
}
.card::before {
    content: "";
    position: absolute;
    width: 220px; height: 220px;
    background: var(--rcm-magenta-soft);
    border-radius: 50%;
    top: -120px; right: -120px;
    filter: blur(40px);
    opacity: 0;
    transition: opacity .35s;
}
.card:hover::before { opacity: 1; }
.card .num {
    font-size: .8rem;
    letter-spacing: .25em;
    color: var(--rcm-text-dim);
    margin-bottom: 1.4rem;
    display: block;
}
.card .icon {
    width: 44px; height: 44px;
    background: var(--rcm-magenta);
    border-radius: 12px;
    display: grid; place-items: center;
    color: #fff;
    margin-bottom: 1.3rem;
    font-size: 1.2rem;
    font-weight: 800;
}
.card h3 { margin-bottom: .5rem; font-size: 1.3rem; }
.card p  { font-size: .95rem; margin: 0; }

/* ---------- BIG SPLIT SECTION ---------- */
.split {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: clamp(2rem, 5vw, 4rem);
    align-items: center;
}
@media (max-width: 880px) { .split { grid-template-columns: 1fr; } }
.split-visual {
    position: relative;
    border-radius: var(--radius-lg);
    overflow: hidden;
    border: 1px solid var(--rcm-border);
    aspect-ratio: 5/4;
    background:
        radial-gradient(circle at 20% 20%, rgba(209, 30, 95, .35), transparent 50%),
        radial-gradient(circle at 80% 80%, rgba(209, 30, 95, .25), transparent 50%),
        var(--rcm-surface);
    display: grid; place-items: center;
    padding: 2rem;
}
.chart-grid {
    width: 100%; height: 100%;
    background-image:
        linear-gradient(rgba(255,255,255,.06) 1px, transparent 1px),
        linear-gradient(90deg, rgba(255,255,255,.06) 1px, transparent 1px);
    background-size: 40px 40px;
    position: absolute; inset: 0;
}

/* ---------- METRIC BARS ---------- */
.metrics { display: flex; flex-direction: column; gap: 1.1rem; width: 100%; position: relative; z-index: 2; }
.metric { background: rgba(0,0,0,.35); border: 1px solid var(--rcm-border-strong); padding: 1rem 1.2rem; border-radius: var(--radius); backdrop-filter: blur(8px); }
.metric .top { display: flex; justify-content: space-between; align-items: baseline; margin-bottom: .55rem; }
.metric .top .label { color: var(--rcm-text-muted); font-size: .85rem; letter-spacing: .08em; text-transform: uppercase; }
.metric .top .val { font-weight: 900; font-size: 1.3rem; letter-spacing: -0.02em; }
.metric .top .val .accent { color: var(--rcm-magenta); }
.bar { height: 6px; background: var(--rcm-border-strong); border-radius: 99px; overflow: hidden; position: relative; }
.bar > span { display: block; height: 100%; background: linear-gradient(90deg, var(--rcm-magenta), var(--rcm-magenta-bright)); border-radius: 99px; transform-origin: left; animation: grow 1.6s var(--ease) both; }
@keyframes grow { from { transform: scaleX(0); } to { transform: scaleX(1); } }

/* ---------- FAQ ---------- */
.faq-list { display: flex; flex-direction: column; gap: .8rem; }
.faq {
    background: var(--rcm-surface);
    border: 1px solid var(--rcm-border);
    border-radius: var(--radius);
    padding: 0;
    overflow: hidden;
    transition: border-color .25s;
}
.faq:hover, .faq[open] { border-color: var(--rcm-border-strong); }
.faq summary {
    list-style: none;
    cursor: pointer;
    padding: 1.3rem 1.5rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 1rem;
    font-weight: 600;
    font-size: 1.02rem;
}
.faq summary::-webkit-details-marker { display: none; }
.faq summary::after {
    content: "+";
    width: 28px; height: 28px;
    border-radius: 50%;
    background: var(--rcm-surface-2);
    border: 1px solid var(--rcm-border-strong);
    display: grid; place-items: center;
    font-weight: 800;
    color: var(--rcm-magenta);
    transition: transform .3s var(--ease), background .25s;
    flex-shrink: 0;
}
.faq[open] summary::after { transform: rotate(45deg); background: var(--rcm-magenta); color: #fff; }
.faq .body { padding: 0 1.5rem 1.4rem; color: var(--rcm-text-muted); font-size: .98rem; }

/* ---------- FORM ---------- */
.form {
    background: var(--rcm-surface);
    border: 1px solid var(--rcm-border);
    border-radius: var(--radius-lg);
    padding: clamp(1.5rem, 4vw, 2.5rem);
}
.form .row { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 1rem; }
@media (max-width: 640px) { .form .row { grid-template-columns: 1fr; } }
.form label {
    display: block;
    font-size: .78rem;
    letter-spacing: .12em;
    text-transform: uppercase;
    color: var(--rcm-text-muted);
    margin-bottom: .4rem;
}
.form input, .form textarea, .form select {
    width: 100%;
    background: var(--rcm-black);
    border: 1px solid var(--rcm-border-strong);
    color: #fff;
    padding: .9rem 1rem;
    border-radius: var(--radius);
    transition: border-color .25s;
    font-size: 1rem;
}
.form input:focus, .form textarea:focus, .form select:focus {
    outline: none;
    border-color: var(--rcm-magenta);
}
.form textarea { min-height: 130px; resize: vertical; }
.form .field { margin-bottom: 1rem; }

/* ---------- BLOG CARDS ---------- */
.blogs-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1.5rem;
}
@media (max-width: 880px) { .blogs-grid { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 600px) { .blogs-grid { grid-template-columns: 1fr; } }
.blog-card {
    background: var(--rcm-surface);
    border: 1px solid var(--rcm-border);
    border-radius: var(--radius-lg);
    overflow: hidden;
    display: flex;
    flex-direction: column;
    transition: transform .3s var(--ease), border-color .3s;
}
.blog-card:hover { transform: translateY(-4px); border-color: var(--rcm-magenta); }
.blog-thumb {
    aspect-ratio: 16/10;
    background: linear-gradient(135deg, #1a1a1a, #050505);
    position: relative;
    overflow: hidden;
}
.blog-thumb::before {
    content: "";
    position: absolute; inset: 0;
    background:
        radial-gradient(circle at var(--x, 30%) var(--y, 40%), rgba(209, 30, 95, .35), transparent 60%);
}
.blog-thumb .badge {
    position: absolute;
    top: 1rem; left: 1rem;
    background: rgba(0, 0, 0, .6);
    border: 1px solid var(--rcm-border-strong);
    padding: .35rem .8rem;
    border-radius: var(--radius-pill);
    font-size: .75rem;
    color: #fff;
    backdrop-filter: blur(6px);
    z-index: 2;
}
.blog-thumb .label-big {
    position: absolute;
    inset: 0;
    display: grid;
    place-items: center;
    color: #fff;
    font-weight: 900;
    font-size: 2rem;
    letter-spacing: -0.03em;
    text-align: center;
    padding: 1rem;
    z-index: 1;
    opacity: .9;
}
.blog-body { padding: 1.5rem; display: flex; flex-direction: column; flex: 1; }
.blog-body .date { font-size: .8rem; color: var(--rcm-text-dim); letter-spacing: .08em; margin-bottom: .8rem; text-transform: uppercase; }
.blog-body h3 { font-size: 1.18rem; margin-bottom: .6rem; line-height: 1.25; }
.blog-body p { font-size: .92rem; margin: 0 0 1.2rem; }
.blog-body .read-more {
    margin-top: auto;
    font-size: .9rem;
    font-weight: 600;
    color: var(--rcm-magenta);
    display: inline-flex; align-items: center; gap: .35rem;
}

/* ---------- LARGE CTA ---------- */
.cta-band {
    background: linear-gradient(135deg, var(--rcm-magenta) 0%, #7a0b34 100%);
    border-radius: var(--radius-lg);
    padding: clamp(2.5rem, 5vw, 4rem);
    text-align: center;
    position: relative;
    overflow: hidden;
}
.cta-band::before {
    content: "";
    position: absolute;
    inset: 0;
    background:
        radial-gradient(circle at 80% 20%, rgba(255,255,255,.25), transparent 50%),
        radial-gradient(circle at 10% 80%, rgba(0,0,0,.3), transparent 50%);
    pointer-events: none;
}
.cta-band > * { position: relative; }
.cta-band h2 { font-size: clamp(2rem, 5vw, 3.4rem); margin-bottom: .8rem; color: #fff; }
.cta-band p  { color: rgba(255,255,255,.85); max-width: 540px; margin: 0 auto 1.8rem; }

/* ---------- FOOTER ---------- */
.ticker {
    background: var(--rcm-magenta);
    color: #fff;
    padding: 1.1rem 0;
    overflow: hidden;
    border-block: 1px solid var(--rcm-magenta);
}
.ticker .marquee-track { animation-duration: 30s; }
.ticker .marquee-item { color: #fff; font-weight: 700; font-size: 1rem; letter-spacing: .04em; }
.ticker .marquee-item::after { background: #fff; }

.footer {
    background: var(--rcm-off-black);
    border-top: 1px solid var(--rcm-border);
    padding: 4rem 0 2rem;
}
.footer-grid {
    display: grid;
    grid-template-columns: 2fr 1fr 1fr 1.4fr;
    gap: 2.5rem;
    margin-bottom: 3rem;
}
@media (max-width: 880px) { .footer-grid { grid-template-columns: 1fr 1fr; } }
@media (max-width: 540px) { .footer-grid { grid-template-columns: 1fr; } }
.footer h4 {
    font-size: .82rem;
    text-transform: uppercase;
    letter-spacing: .15em;
    color: var(--rcm-text-muted);
    margin-bottom: 1.2rem;
}
.footer ul { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: .7rem; }
.footer a { color: var(--rcm-text-muted); font-size: .95rem; transition: color .2s; }
.footer a:hover { color: var(--rcm-magenta); }
.footer .brand-block p { font-size: .95rem; max-width: 320px; margin: 1rem 0 1.5rem; }
.footer .contact-item { font-size: .9rem; color: var(--rcm-text-muted); margin-bottom: .4rem; }
.footer .contact-item strong { color: #fff; display: block; font-size: .78rem; text-transform: uppercase; letter-spacing: .1em; margin-bottom: .2rem; }
.footer-bottom {
    border-top: 1px solid var(--rcm-border);
    padding-top: 1.5rem;
    display: flex;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 1rem;
    font-size: .85rem;
    color: var(--rcm-text-dim);
}

/* ---------- PROCESS STEPS ---------- */
.process {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 1.2rem;
    counter-reset: step;
}
@media (max-width: 880px) { .process { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 540px) { .process { grid-template-columns: 1fr; } }
.step {
    background: var(--rcm-surface);
    border: 1px solid var(--rcm-border);
    border-radius: var(--radius-lg);
    padding: 2rem 1.5rem;
    position: relative;
    counter-increment: step;
}
.step::before {
    content: "0" counter(step);
    position: absolute;
    top: 1.5rem; right: 1.5rem;
    font-size: 2.2rem;
    font-weight: 900;
    color: var(--rcm-magenta);
    line-height: 1;
    letter-spacing: -0.04em;
