cd /sessions/trusting-jolly-lamport/mnt/outputs && python3 -c "
from html.parser import HTMLParser
import os

class Validator(HTMLParser):
    def __init__(self):
        super().__init__()
        self.stack = []
        self.errors = []
        self.void = {'meta','link','br','hr','img','input','source','area','base','col','embed','param','track','wbr'}
    def handle_starttag(self, tag, attrs):
        if tag not in self.void:
            self.stack.append(tag)
    def handle_endtag(self, tag):
        if tag in self.void: return
        if self.stack and self.stack[-1] == tag:
            self.stack.pop()
        else:
            self.errors.append(f'mismatch: expected </{self.stack[-1] if self.stack else \"?\"}>, got </{tag}>')

for f in ['index.html','services.html','blogs.html','contact.html']:
    v = Validator()
    v.feed(open(f).read())
    extra = v.stack
    print(f'{f}: errors={len(v.errors)} unclosed={extra[:5] if extra else None}')
"

