    cursor: pointer;
}
.video-card:hover .play-btn { transform: scale(1.08); background: var(--rcm-magenta-bright); }
.play-btn::after {
    content: "";
    width: 0; height: 0;
    border-left: 18px solid #fff;
    border-top: 11px solid transparent;
    border-bottom: 11px solid transparent;
    margin-left: 5px;
}
.video-quote {
    position: absolute;
    left: 1.3rem; right: 1.3rem; bottom: 1.3rem;
    color: #fff;
    font-weight: 600;
    font-size: 1rem;
    line-height: 1.35;
    z-index: 3;
    text-shadow: 0 2px 12px rgba(0,0,0,.6);
}
.video-tag {
    position: absolute;
    top: 1rem; left: 1rem;
    z-index: 3;
    background: rgba(0,0,0,.6);
    border: 1px solid var(--rcm-border-strong);
    padding: .35rem .8rem;
    border-radius: var(--radius-pill);
    font-size: .72rem;
    font-weight: 600;
    letter-spacing: .12em;
    text-transform: uppercase;
    color: #fff;
    backdrop-filter: blur(6px);
}
.video-meta {
    padding: 1.3rem 1.4rem 1.5rem;
    display: flex;
    align-items: center;
    gap: .9rem;
    border-top: 1px solid var(--rcm-border);
}
.avatar {
    width: 44px; height: 44px;
    border-radius: 50%;
    background: var(--rcm-magenta);
    color: #fff;
    display: grid; place-items: center;
    font-weight: 800;
    font-size: 1rem;
    flex-shrink: 0;
}
.video-meta .name {
    font-weight: 700;
    font-size: .98rem;
    line-height: 1.2;
}
.video-meta .role {
    font-size: .82rem;
    color: var(--rcm-text-muted);
    margin-top: .1rem;
}
.video-meta .result {
    margin-left: auto;
    text-align: right;
    font-weight: 800;
    color: var(--rcm-magenta);
    font-size: 1rem;
    line-height: 1;
    letter-spacing: -0.02em;
}
.video-meta .result span {
    display: block;
    color: var(--rcm-text-muted);
    font-size: .68rem;
    font-weight: 600;
    letter-spacing: .12em;
    text-transform: uppercase;
    margin-top: .25rem;
}

/* ---------- CALENDLY BAND ---------- */
.calendly-band {
    background: linear-gradient(135deg, #100008 0%, #14060f 50%, #1a0c14 100%);
    border: 1px solid var(--rcm-magenta);
    border-radius: var(--radius-lg);
    padding: clamp(2.5rem, 6vw, 4.5rem);
    text-align: center;
    position: relative;
    overflow: hidden;
}
.calendly-band::before {
    content: "";
    position: absolute;
    width: 600px; height: 600px;
    background: radial-gradient(closest-side, rgba(209, 30, 95, .35), transparent 70%);
    top: -200px; left: 50%;
    transform: translateX(-50%);
    filter: blur(20px);
    pointer-events: none;
}
.calendly-band > * { position: relative; z-index: 1; }
.calendly-band .label {
    display: inline-flex;
    align-items: center; gap: .55rem;
    background: rgba(209, 30, 95, .15);
    border: 1px solid var(--rcm-magenta);
    color: #fff;
    padding: .5rem 1.1rem;
    border-radius: var(--radius-pill);
    font-size: .8rem;
    font-weight: 600;
    letter-spacing: .15em;
    text-transform: uppercase;
    margin-bottom: 1.5rem;
}
.calendly-band .label::before {
    content: "";
    width: 8px; height: 8px;
    background: #2ecc71;
    border-radius: 50%;
    box-shadow: 0 0 12px #2ecc71;
    animation: pulse 1.6s ease-in-out infinite;
}
@keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: .35; } }
.calendly-band h2 {
    font-size: clamp(2.2rem, 5vw, 3.8rem);
    margin-bottom: 1rem;
}
.calendly-band .sub {
    color: var(--rcm-text-muted);
    max-width: 600px;
    margin: 0 auto 2rem;
    font-size: 1.05rem;
}
.calendly-band .perks {
    display: flex;
    justify-content: center;
    gap: 1.5rem;
    flex-wrap: wrap;
    margin-top: 1.8rem;
    font-size: .88rem;
    color: var(--rcm-text-muted);
}
.calendly-band .perks > div {
    display: inline-flex;
    align-items: center; gap: .5rem;
}
.calendly-band .perks > div::before {
    content: "✓";
    color: var(--rcm-magenta);
    font-weight: 900;
    width: 18px; height: 18px;
    border-radius: 50%;
    background: var(--rcm-magenta-soft);
    display: grid; place-items: center;
    font-size: .7rem;
}

