        iframe.allowFullscreen = true;
        thumb.appendChild(iframe);
    };
    thumb.addEventListener('click', play);
    thumb.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); play(); }
    });
});

