from html.parser import HTMLParser
class V(HTMLParser):
    def __init__(self):
        super().__init__()
        self.s = []
        self.e = []
        self.v = {'meta','link','br','hr','img','input','source','area','base','col','embed','param','track','wbr','iframe'}
    def handle_starttag(self, t, a):
        if t not in self.v: self.s.append(t)
    def handle_endtag(self, t):
        if t in self.v: return
        if self.s and self.s[-1] == t: self.s.pop()
